module top_module(
    X    ,
    A    ,
    SLEEP
);// Module ports
    output X    ;
    input  A    ;
    input  SLEEP;

    // Module supplies
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Local signals
    wire NOT_WAKEUP;

    //  Name  Output  Other arguments
    not not0 (NOT_WAKEUP, SLEEP          );
    and and0 (X     , A, NOT_WAKEUP      );

endmodule
